mapper.select:
${pagingTop}
SELECT
	idx, login_type, member_id, homepage_id, user_agent, ip,
	TO_CHAR(login_date, 'YYYY-MM-DD HH24:MI:SS') AS login_date,
	(SELECT z.homepage_name FROM cms_homepage z WHERE z.homepage_id = a.homepage_id) AS homepage_name
FROM
	LOGIN_LOG a
WHERE 1=1
AND login_type = #{login_type}
AND member_id = #{member_id}
ORDER BY login_date DESC
${pagingBottom}

mapper.insert:
INSERT INTO LOGIN_LOG (
	idx, login_type, member_id, homepage_id, login_date, ip, user_agent
) VALUES (
	LOGIN_LOG_SEQ.NEXTVAL, #{login_type}, #{member_id}, #{homepage_id}, SYSDATE, #{ip}, #{user_agent}
)

